const DL_PDF_DATA = [
  { filename: "01_shugyo_kisoku.pdf", title: "就業規則 作成テンプレート集", emoji: "📋", b64: "" },
  { filename: "02_joseikin_manual.pdf", title: "助成金申請 完全マニュアル", emoji: "💰", b64: "" },
  { filename: "03_rodo_risk_checklist.pdf", title: "労務リスク 50項目チェックリスト", emoji: "⚖️", b64: "" },
  { filename: "04_shakai_hoken_hayamihyo.pdf", title: "社会保険料 早見表 2025年度版", emoji: "📊", b64: "" },
  { filename: "05_hajimete_yatofu_guide.pdf", title: "はじめて社員を雇う時の手続き完全ガイド", emoji: "🏢", b64: "" },
  { filename: "06_36kyotei_guide.pdf", title: "36協定 作成・届出 実務ガイドブック", emoji: "🕐", b64: "" },
];

// =============================================
// ダウンロードページ JS
// =============================================
(function() {
    const DL_ITEMS = [
        { emoji: '📋', title: '就業規則 作成テンプレート集' },
        { emoji: '💰', title: '助成金申請 完全マニュアル' },
        { emoji: '⚖️', title: '労務リスク 50項目チェックリスト' },
        { emoji: '📊', title: '社会保険料 早見表 2025年度版' },
        { emoji: '🏢', title: 'はじめて社員を雇う時の手続き完全ガイド' },
        { emoji: '🕐', title: '36協定 作成・届出 実務ガイドブック' }
    ];
    let currentIdx  = 0;
    let currentMode = 'single';

    window.dlOpenModal = function(idx) {
        currentIdx = idx;
        const item = DL_ITEMS[idx];
        document.getElementById('dl-modal-emoji').textContent = item.emoji;
        document.getElementById('dl-modal-title').textContent = item.title;
        ['dl-company','dl-name','dl-email'].forEach(id => document.getElementById(id).value = '');
        document.getElementById('dl-newsletter').checked = true;
        document.getElementById('dl-form-error').classList.add('hidden');
        document.getElementById('dl-form-area').classList.remove('hidden');
        document.getElementById('dl-success-area').classList.add('hidden');
        document.getElementById('dl-modal-overlay').style.display = 'flex';
        document.body.style.overflow = 'hidden';
        currentMode = 'single';
    };

    window.dlCloseModal = function() {
        document.getElementById('dl-modal-overlay').style.display = 'none';
        document.body.style.overflow = '';
    };

    window.dlOverlayClick = function(e) {
        if (e.target === document.getElementById('dl-modal-overlay')) dlCloseModal();
    };

    function validateEmail(e) { return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e); }

    function goToThankyou(mode, idx) {
        dlCloseModal();
        showPage('dl-thankyou');
        document.getElementById('dl-ty-single').classList.add('hidden');
        document.getElementById('dl-ty-all').classList.add('hidden');

        if (mode === 'single') {
            const item = DL_ITEMS[idx];
            document.getElementById('dl-ty-heading').textContent = 'ご登録ありがとうございます！';
            document.getElementById('dl-ty-subtext').textContent = '以下のボタンから資料をダウンロードしてください。';
            document.getElementById('dl-ty-emoji').textContent   = item.emoji;
            document.getElementById('dl-ty-title').textContent   = item.title;
            document.getElementById('dl-ty-btn-single').dataset.idx = idx;
            document.getElementById('dl-ty-single').classList.remove('hidden');
            const grid = document.getElementById('dl-ty-others-grid');
            grid.innerHTML = '';
            DL_ITEMS.forEach(function(it, i) {
                if (i === idx) return;
                const btn = document.createElement('button');
                btn.className = 'flex items-center gap-3 p-4 rounded-2xl border-2 border-gray-100 hover:border-blue-300 hover:bg-blue-50 transition text-left group';
                btn.innerHTML = '<span class="text-2xl flex-shrink-0">' + it.emoji + '</span>'
                    + '<div><p class="font-bold text-blue-900 text-sm leading-tight group-hover:text-blue-700">' + it.title + '</p>'
                    + '<p class="text-xs text-gray-400 mt-0.5">クリックしてダウンロード</p></div>';
                btn.onclick = function() { dlTyDownloadByIndex(i); };
                grid.appendChild(btn);
            });
        } else {
            document.getElementById('dl-ty-heading').textContent = '全資料のご登録ありがとうございます！';
            document.getElementById('dl-ty-subtext').textContent = '各ボタンをクリックして資料をダウンロードしてください。';
            document.getElementById('dl-ty-all').classList.remove('hidden');
            const grid = document.getElementById('dl-ty-all-grid');
            grid.innerHTML = '';
            DL_ITEMS.forEach(function(it, i) {
                const btn = document.createElement('button');
                btn.className = 'flex items-center gap-3 p-4 rounded-2xl border-2 border-gray-100 hover:border-blue-300 hover:bg-blue-50 transition text-left group w-full';
                btn.innerHTML = '<span class="text-2xl flex-shrink-0">' + it.emoji + '</span>'
                    + '<div class="flex-1 min-w-0"><p class="font-bold text-blue-900 text-sm leading-tight">' + it.title + '</p>'
                    + '<p class="text-xs text-indigo-500 mt-0.5 font-semibold">↓ ダウンロード</p></div>'
                    + '<svg class="w-5 h-5 text-blue-400 flex-shrink-0" fill="currentColor" viewBox="0 0 20 20"><path fill-rule="evenodd" d="M3 17a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1zm3.293-7.707a1 1 0 011.414 0L9 10.586V3a1 1 0 112 0v7.586l1.293-1.293a1 1 0 111.414 1.414l-3 3a1 1 0 01-1.414 0l-3-3a1 1 0 010-1.414z" clip-rule="evenodd"/></svg>';
                btn.onclick = function() { dlTyDownloadByIndex(i); };
                grid.appendChild(btn);
            });
        }
        window.scrollTo({ top: 0, behavior: 'smooth' });
    }

    function downloadPDF(idx) {
        const pdfObj = DL_PDF_DATA[idx];
        const binary = atob(pdfObj.b64);
        const bytes  = new Uint8Array(binary.length);
        for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
        const blob = new Blob([bytes], { type: 'application/pdf' });
        const url  = URL.createObjectURL(blob);
        const a    = document.createElement('a');
        a.href     = url;
        a.download = pdfObj.filename;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        setTimeout(() => URL.revokeObjectURL(url), 5000);
    }

    window.dlTyDownloadSingle = function() {
        const idx = parseInt(document.getElementById('dl-ty-btn-single').dataset.idx || '0');
        downloadPDF(idx);
    };

    window.dlTyDownloadByIndex = function(idx) { downloadPDF(idx); };

    window.dlSubmit = function() {
        const name  = document.getElementById('dl-name').value.trim();
        const email = document.getElementById('dl-email').value.trim();
        const errEl = document.getElementById('dl-form-error');
        if (!name || !email || !validateEmail(email)) {
            errEl.classList.remove('hidden');
            return;
        }
        errEl.classList.add('hidden');
        const btn = document.getElementById('dl-submit-btn');
        btn.disabled = true;
        btn.innerHTML = '<svg class="w-5 h-5 animate-spin" fill="none" viewBox="0 0 24 24"><circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"></circle><path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"></path></svg> 処理中...';
        setTimeout(function() {
            btn.disabled = false;
            btn.innerHTML = '<svg class="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fill-rule="evenodd" d="M3 17a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1zm3.293-7.707a1 1 0 011.414 0L9 10.586V3a1 1 0 112 0v7.586l1.293-1.293a1 1 0 111.414 1.414l-3 3a1 1 0 01-1.414 0l-3-3a1 1 0 010-1.414z" clip-rule="evenodd"/></svg> ダウンロードリンクを受け取る';
            goToThankyou('single', currentIdx);
            setTimeout(function() { downloadPDF(currentIdx); }, 400);
        }, 700);
    };

    window.dlBannerRegister = function() {
        const email = document.getElementById('dl-banner-email').value.trim();
        if (!email || !validateEmail(email)) {
            document.getElementById('dl-banner-email').classList.add('ring-2','ring-red-400');
            document.getElementById('dl-banner-email').focus();
            return;
        }
        document.getElementById('dl-banner-email').classList.remove('ring-2','ring-red-400');
        document.getElementById('dl-banner-form').classList.add('hidden');
        document.getElementById('dl-banner-done').classList.remove('hidden');
        setTimeout(function() { goToThankyou('all', -1); }, 800);
    };

    document.addEventListener('keydown', function(e) {
        if (e.key === 'Escape') dlCloseModal();
    });
})();
